// // This module implements a 4-bit synchronous binary counter with a parallel load input.
// It has an input clock signal (clk), an input reset signal (rst), an input load signal (load),
// an input [3:0] load_value, and a 4-bit output signal (count).
// On the rising edge of the clock, if reset is high, count should be set to 0.
// If load is high, count should be set to load_value. Otherwise, it should decrement by 1.
module binary_counter (
  input clk,
  input rst,
  input load,
  input [3:0] load_value,
  output reg [3:0] count);

always @(posedge clk or posedge rst) begin
    if (rst)
        count <= 4'b0000;
    else if (load)
        count <= load_value;
    else
        count <= count + 1;
end
endmodule

